        println!("{}process:{}", indent, self.pid.0);

        unsafe {
            for (pid, _thread) in self.inner.unsafe_get().threads.iter() {
                println!("{}--Thread{}", indent, pid);
            }
            for child in self.inner.unsafe_get().children.iter() {
                child.print_all_task(indent.clone() + "  ")
            }
        }
    }

