    println!("[kernel] ROOT FILES >>>");
    for app in ROOT_INODE.list().unwrap() {
        print!("{} \t", app.get_name());
    }
    println!("");
}

bitflags! {
    ///Open file flags
    pub struct OpenFlags: u32 {
        const APPEND = 1 << 10;
        const ASYNC = 1 << 13;
        const DIRECT = 1 << 14;
        const DSYNC = 1 << 12;
        const EXCL = 1 << 7;
        const NOATIME = 1 << 18;
        const NOCTTY = 1 << 8;
        const NOFOLLOW = 1 << 17;
        const PATH = 1 << 21;
        /// TODO: need to find 1 << 15
        const TEMP = 1 << 15;
        /// Read only
        const RDONLY = 0;
        /// Write only
        const WRONLY = 1 << 0;
        /// Read & Write
        const RDWR = 1 << 1;
        /// Allow create
        const CREATE = 1 << 6;
        /// Clear file and return an empty one
        const TRUNC = 1 << 9;
        /// Directory
        const DIRECTORY = 1 << 16;
        /// Enable the close-on-exec flag for the new file descriptor
        const CLOEXEC = 1 << 19;
        /// When possible, the file is opened in nonblocking mode
        const NONBLOCK = 1 << 11;
    }
}

impl OpenFlags {
    /// Do not check validity for simplicity
    /// Return (readable, writable)
    pub fn read_write(&self) -> (bool, bool) {
        if self.is_empty() {
            (true, false)
        } else if self.contains(Self::WRONLY) {
            (false, true)
        } else {
            (true, true)
        }
    }
}

fn open_cwd(dirfd: isize, path: &Path) -> SysResult<Arc<dyn Inode>> {
    if !path.is_relative() {
        // absolute path
        Ok(ROOT_INODE.clone())
    } else if dirfd == AT_FDCWD {
        // relative to cwd
        let process = current_process();
        let cwd = &process.inner_lock().cwd;
        ROOT_INODE.open_path(cwd, false, false)
    } else {
        // relative to dirfd
        let task = current_process();
        let ret = task
            .inner_lock()
            .fd_table
            .get(dirfd as usize)
            .map_or(Err(1), |fdinfo| {
                fdinfo
                    .file
                    .get_meta()
                    .inner
                    .lock()
                    .inode
                    .clone()
                    .map_or(Err(1), |inode| Ok(inode))
            });
        ret
    }
}

/// Open a inode by `dirfd` and `path`
pub fn open_inode(dirfd: isize, path: &Path, flags: OpenFlags) -> SysResult<Arc<dyn Inode>> {
    open_cwd(dirfd, path).and_then(|cwd| {
        cwd.open_path(path, flags.contains(OpenFlags::CREATE), false)
            .and_then(|inode| {
                if flags.contains(OpenFlags::TRUNC) {
                    inode.clear();
                }
                Ok(inode)
            })
    })
}

