            let mode = dirent_inodetype_2_inodemode(unsafe { entry.inner.inode_type });
            let data_size = Self::get_size_from_ino(&self.fs, ino as u64);

            let inode_meta = InodeMeta::new(Some(this.clone()), path, mode, data_size, ino);
