fn dirent_inodetype_2_inodemode(inode_type: u8) -> InodeMode {
    match inode_type {
        1 => InodeMode::FileREG,
        2 => InodeMode::FileDIR,
        3 => InodeMode::FileCHR,
        4 => InodeMode::FileBLK,
        5 => InodeMode::FileFIFO,
        6 => InodeMode::FileSOCK,
        7 => InodeMode::FileLNK,
        _ => panic!("[dirent_inodetype_2_inodemode] inode type should not be unknown"),
    }
}

