    fn load_children_from_disk(&self, _this: Arc<dyn Inode>) {
        panic!("[MountsInode::load_children_from_disk] invalid")
    }
    fn clear(&self) {
        panic!("[MountsInode::clear] invalid")
    }
}

use alloc::sync::Arc;

use super::{
    devfs::dev::DevInode,
    inode::Inode,
    os_inode::{list_apps, ROOT_INODE},
    procfs::proc::ProcInode,
};

/// used on start of os
pub fn init() {
    mount_fs();
    list_apps();
}

fn mount_fs() {
    let root_meta = ROOT_INODE.get_meta();
    let mut root_inner = root_meta.inner.lock();

    // 'mount' inner fs es
    let dev: Arc<dyn Inode> = Arc::new(DevInode::new(ROOT_INODE.clone()));
    let proc: Arc<dyn Inode> = Arc::new(ProcInode::new(ROOT_INODE.clone()));
    root_inner.children.insert(dev.get_name(), dev.clone());
    root_inner.children.insert(proc.get_name(), proc.clone());
}

use std::fs::{read_dir, File};
use std::io::{Result, Write};

fn main() {
    println!("cargo:rerun-if-changed=../user/src/");
    println!("cargo:rerun-if-changed={}", TARGET_PATH);
    insert_app_data().unwrap();
}

static TARGET_PATH: &str = "../user/target/riscv64gc-unknown-none-elf/release/";

fn insert_app_data() -> Result<()> {
    let mut f = File::create("src/link_app.S").unwrap();
    let mut apps: Vec<_> = read_dir("../user/src/bin")
        .unwrap()
        .into_iter()
        .filter(|dir_entry| dir_entry.as_ref().unwrap().file_type().unwrap().is_file())
        .map(|dir_entry| {
            let mut name_with_ext = dir_entry.unwrap().file_name().into_string().unwrap();
            name_with_ext.drain(name_with_ext.find('.').unwrap()..name_with_ext.len());
            name_with_ext
        })
        .collect();
    apps.sort();

    writeln!(
        f,
        r#"
    .align 3
    .section .data
    .global _num_app
_num_app:
    .quad {}"#,
        apps.len()
    )?;

    for i in 0..apps.len() {
        writeln!(f, r#"    .quad app_{}_start"#, i)?;
    }
    writeln!(f, r#"    .quad app_{}_end"#, apps.len() - 1)?;

    writeln!(
        f,
        r#"
    .global _app_names
_app_names:"#
    )?;
    for app in apps.iter() {
        writeln!(f, r#"    .string "{}""#, app)?;
    }

    for (idx, app) in apps.iter().enumerate() {
        println!("app_{}: {}", idx, app);
        writeln!(
            f,
            r#"
    .section .data
    .global app_{0}_start
    .global app_{0}_end
    .align 3
app_{0}_start:
    .incbin "{2}{1}"
app_{0}_end:"#,
            idx, app, TARGET_PATH
        )?;
    }
    Ok(())
}

